// Build the exact payload that goes into Airtable Create. Map Automatically uses these field names.
const item = $input.first();
const rawBody = (item.json && item.json.body) ? item.json.body : item.json;
const body = rawBody || {};

const safe = (v, fb = '') => (v === undefined || v === null) ? fb : String(v).trim();
const num = (v, fb = 0) => { const n = Number(v); return Number.isFinite(n) ? n : fb; };

// 16-char alphanumeric token (lowercase). Always exactly 16 chars; never breaks URLs.
const token = (Math.random().toString(36).substring(2, 10) + Math.random().toString(36).substring(2, 10))
  .toLowerCase().replace(/[^a-z0-9]/g, '').padEnd(16, 'x').substring(0, 16);

return [{
  json: {
    magic_token: token,
    student_name: safe(body.student_name, 'Unknown'),
    parent_name: safe(body.parent_name, 'Parent'),
    parent_whatsapp: safe(body.parent_whatsapp).replace(/\s+/g, ''),
    parent_email: safe(body.parent_email).toLowerCase(),
    course: safe(body.course, 'Maths'),
    classes_count: num(body.classes_count, 1),
    amount: num(body.amount, 0),
    currency: safe(body.currency, 'INR'),
    sales_agent: safe(body.sales_agent, 'Unknown'),
    lead_source: safe(body.lead_source, 'Other'),
    sale_type: safe(body.sale_type, 'New sale'),
    demo_tutor: safe(body.demo_tutor, ''),
    preferred_timing: safe(body.preferred_timing, ''),
    status: 'Pending',
    whatsapp_sent: false,
    email_sent: false,
    parent_confirmed: false,
    meet_created: false
  }
}];

// Build minimal payload for the Update node — only the 3 fields we want to change, plus id for matching.
const createOut = $('Airtable: Create Enrollment').first().json;
const recordId = createOut && createOut.id;
if (!recordId) {
  throw new Error('Airtable Create did not return a record id');
}
return [{ json: { id: recordId, whatsapp_sent: true, email_sent: true, status: 'Notified' } }];
